#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        uint64_t N; if(scanf("%llu",&N)!=1) break;
        if(N>1 && ((N & (N+1))==0)){
            uint64_t M = (N-1)/2;
            printf("%llu\n",M);
        }else{
            printf("-1\n");
        }
    }
    return 0;
}

