import sys
def solve():
    data = sys.stdin.read().split()
    if not data:
        return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        n = int(data[idx]); idx+=1
        if n>1 and (n & (n+1))==0:
            out.append(str((n-1)//2))
        else:
            out.append('-1')
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    solve()

